const expectedSecret = $env.TELEGRAM_WEBHOOK_SECRET;
if (!expectedSecret) {
  throw new Error('Missing TELEGRAM_WEBHOOK_SECRET in n8n runtime environment');
}

const headers = $json.headers || {};
const body = $json.body || $json;
const receivedSecret = headers['x-telegram-bot-api-secret-token'] || headers['X-Telegram-Bot-Api-Secret-Token'];

if (receivedSecret !== expectedSecret) {
  return [];
}

const message = body.message || body.edited_message || body.business_message || body.edited_business_message || body.channel_post || body.edited_channel_post;
if (!message) {
  return [];
}

const text = (message.text || message.caption || '').trim();
if (!text) {
  return [];
}

const chat = message.chat || {};
const from = message.from || message.sender_user || {};
const tenantId = $env.DEFAULT_TENANT_ID || $env.TENANT_ID || 'default';

return [{
  json: {
    tenant_id: tenantId,
    channel: 'telegram',
    thread_id: String(chat.id || from.id || body.update_id),
    sender_id: String(from.id || chat.id || body.update_id),
    sender_username: from.username || chat.username || null,
    sender_display_name: [from.first_name, from.last_name].filter(Boolean).join(' ') || chat.title || null,
    message_text: text,
    message_id: message.message_id ? String(message.message_id) : String(body.update_id),
    telegram_chat_id: chat.id,
    telegram_update_id: body.update_id,
    raw_event: body
  }
}];

const normalized = $('Validate Telegram Secret + Normalize').first().json;
const core = $json || {};
const status = String(core.status || core.decision || 'answered');
const response = String(core.response || core.answer || core.message || '').trim();

if (!response || status === 'silent' || core.silent === true) {
  return [];
}

const text = response.length > 4096 ? `${response.slice(0, 4050)}...` : response;
const needsEscalation = status === 'escalated' || core.escalated === true || core.escalate === true;

return [{
  json: {
    tenant_id: normalized.tenant_id,
    channel: 'telegram',
    thread_id: normalized.thread_id,
    telegram_chat_id: normalized.telegram_chat_id,
    text,
    status,
    confidence: typeof core.confidence === 'number' ? core.confidence : null,
    needs_escalation: needsEscalation,
    escalation_reason: core.escalation_reason || core.reason || (needsEscalation ? 'telegram_human_handoff' : null),
    escalation_summary: core.escalation_summary || core.summary || text.slice(0, 500)
  }
}];
